#[test]
fn test_config_chunking_prepend_heading_context() {
    // Tests markdown chunker prepends heading hierarchy to chunk content
    let path: &str = concat!(
        env!("CARGO_MANIFEST_DIR"),
        "/../../test_documents/",
        "markdown/extraction_test.md"
    );
    let mime_type: Option<String> = None;
    let config_json = serde_json::json!({"chunking": {"chunker_type": "markdown", "max_chars": 300, "max_overlap": 50, "prepend_heading_context": true}});
    let config = serde_json::from_value(config_json).unwrap();
    let stream = extract_file_sync(path, mime_type.as_deref(), &config).expect("should succeed");
    let chunks: Vec<_> = tokio_stream::StreamExt::collect::<Vec<_>>(stream)
        .await
        .into_iter()
        .map(|r| r.expect("stream item failed"))
        .collect();
    assert!(
        result.content.len() >= 10,
        "expected length >= 10, got {}",
        result.content.len()
    );
    assert!(chunks.len() >= 2 as usize, "expected >= 2 chunks");
    assert!(
        result
            .chunks
            .as_ref()
            .is_some_and(|chunks| !chunks.is_empty() && chunks.iter().all(|c| !c.content.is_empty())),
        "expected all chunks to have content"
    );
    assert!(result.chunks_have_heading_context, "expected true");
    assert!(result.first_chunk_starts_with_heading, "expected true");
}

